dslRule:
@id: jdt.internal.formatter.versioner.currentversion.update.to.20
/*!description: Updates the internal formatter profile version from VERSION_19 to VERSION_20.*/
/*!severity: info*/
org.eclipse.jdt.internal.ui.preferences.formatter.ProfileVersioner.CURRENT_VERSION = org.eclipse.jdt.internal.ui.preferences.formatter.ProfileVersioner.VERSION_19
=> org.eclipse.jdt.internal.ui.preferences.formatter.ProfileVersioner.CURRENT_VERSION = org.eclipse.jdt.internal.ui.preferences.formatter.ProfileVersioner.VERSION_20
;;

/*!id: jdt.internal.staticimport.getstaticimportfavorites.move*/
/*!description: Moves the getStaticImportFavorites method call from SimilarElementsRequestor to JavaModelUtil, updating the call site.*/
/*!severity: info*/
org.eclipse.jdt.internal.ui.text.correction.SimilarElementsRequestor.getStaticImportFavorites($cu, $elementName, $isMethod, $favourites)
=> org.eclipse.jdt.internal.corext.util.JavaModelUtil.getStaticImportFavorites($cu, $elementName, $isMethod, $favourites)
;;

/*!id: anonymous.runnable.to.lambda*/
/*!description: Convert anonymous Runnable to lambda expression.*/
/*!severity: info*/
new java.lang.Runnable() { @java.lang.Override public void run() { $body$ } }
=> () -> { $body$ }
;;

