dslRuleAfterChange:
/* Hypothetical rule if multi-statement rewrites were supported */
if ($f1 == null) {
    if ($f2 != null) {
        return false;
    }
} else if (!$f1.equals($f2)) {
    return false;
}
=>
if (!java.util.Objects.equals($f1, $f2)) {
    return false;
}
;;

